169	static int web_tcp_connect(const char *host, int port, int timeout_ms,
170	                           char *err, size_t err_len) {
171	    char service[32];
172	    snprintf(service, sizeof(service), "%d", port);
173	    struct addrinfo hints;
174	    memset(&hints, 0, sizeof(hints));
175	    hints.ai_socktype = SOCK_STREAM;
176	    hints.ai_family = AF_UNSPEC;
177	    struct addrinfo *res = NULL;
178	    int gai = getaddrinfo(host, service, &hints, &res);
179	    if (gai != 0) {
180	        web_set_err(err, err_len, "getaddrinfo %s: %s", host, gai_strerror(gai));
181	        return -1;
182	    }
183	
184	    int fd = -1;
185	    for (struct addrinfo *ai = res; ai; ai = ai->ai_next) {
186	        fd = socket(ai->ai_family, ai->ai_socktype, ai->ai_protocol);
187	        if (fd < 0) continue;
188	        int flags = fcntl(fd, F_GETFL, 0);
189	        if (flags >= 0) fcntl(fd, F_SETFL, flags | O_NONBLOCK);
190	        int rc = connect(fd, ai->ai_addr, ai->ai_addrlen);
191	        if (rc == 0) {
192	            if (flags >= 0) fcntl(fd, F_SETFL, flags);
193	            break;
194	        }
195	        if (errno == EINPROGRESS) {
196	            struct pollfd pfd = {.fd = fd, .events = POLLOUT};
197	            rc = poll(&pfd, 1, timeout_ms);
198	            if (rc > 0) {
199	                int soerr = 0;
200	                socklen_t slen = sizeof(soerr);
201	                getsockopt(fd, SOL_SOCKET, SO_ERROR, &soerr, &slen);
202	                if (soerr == 0) {
203	                    if (flags >= 0) fcntl(fd, F_SETFL, flags);
204	                    break;
205	                }
206	                errno = soerr;
207	            }
208	        }
209	        close(fd);
210	        fd = -1;
211	    }
212	    freeaddrinfo(res);
213	    if (fd < 0) web_set_err(err, err_len, "connect %s:%d failed: %s",
214	                            host, port, strerror(errno));
215	    return fd;
216	}
