234	static ssize_t web_read_some(int fd, char *buf, size_t len, int timeout_ms) {
235	    struct pollfd pfd = {.fd = fd, .events = POLLIN};
236	    int rc = poll(&pfd, 1, timeout_ms);
237	    if (rc <= 0) return rc == 0 ? 0 : -1;
238	    for (;;) {
239	        ssize_t n = read(fd, buf, len);
240	        if (n < 0 && errno == EINTR) continue;
241	        return n;
242	    }
243	}
