320	static void web_random_bytes(unsigned char *buf, size_t len) {
321	    int fd = open("/dev/urandom", O_RDONLY);
322	    if (fd >= 0) {
323	        size_t off = 0;
324	        while (off < len) {
325	            ssize_t n = read(fd, buf + off, len - off);
326	            if (n < 0 && errno == EINTR) continue;
327	            if (n <= 0) break;
328	            off += (size_t)n;
329	        }
330	        close(fd);
331	        if (off == len) return;
332	    }
333	    uint64_t x = (uint64_t)time(NULL) ^ ((uint64_t)getpid() << 32);
334	    for (size_t i = 0; i < len; i++) {
335	        x = x * 6364136223846793005ULL + 1;
336	        buf[i] = (unsigned char)(x >> 32);
337	    }
338	}
339	
340	static char *web_base64(const unsigned char *data, size_t len) {
341	    static const char tab[] =
342	        "ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789+/";
343	    size_t outlen = ((len + 2) / 3) * 4;
344	    char *out = web_xmalloc(outlen + 1);
345	    size_t j = 0;
346	    for (size_t i = 0; i < len; i += 3) {
347	        uint32_t v = (uint32_t)data[i] << 16;
348	        if (i + 1 < len) v |= (uint32_t)data[i + 1] << 8;
349	        if (i + 2 < len) v |= data[i + 2];
350	        out[j++] = tab[(v >> 18) & 63];
351	        out[j++] = tab[(v >> 12) & 63];
352	        out[j++] = (i + 1 < len) ? tab[(v >> 6) & 63] : '=';
353	        out[j++] = (i + 2 < len) ? tab[v & 63] : '=';
354	    }
355	    out[j] = '\0';
356	    return out;
357	}
358	
359	static char *web_json_quote(const char *s) {
360	    web_buf b = {0};
361	    web_buf_puts(&b, "\"");
362	    for (const unsigned char *p = (const unsigned char *)s; p && *p; p++) {
363	        unsigned char c = *p;
364	        switch (c) {
365	        case '\\': web_buf_puts(&b, "\\\\"); break;
366	        case '"': web_buf_puts(&b, "\\\""); break;
367	        case '\n': web_buf_puts(&b, "\\n"); break;
368	        case '\r': web_buf_puts(&b, "\\r"); break;
369	        case '\t': web_buf_puts(&b, "\\t"); break;
370	        default:
371	            if (c < 0x20) {
372	                char tmp[8];
373	                snprintf(tmp, sizeof(tmp), "\\u%04x", c);
374	                web_buf_puts(&b, tmp);
375	            } else {
376	                web_buf_append(&b, (const char *)&c, 1);
377	            }
378	            break;
379	        }
380	    }
381	    web_buf_puts(&b, "\"");
382	    return web_buf_take(&b);
383	}
384	
385	static int web_ws_connect(const char *ws_url, cdp_ws *ws,
386	                          char *err, size_t err_len) {
387	    const char *p = ws_url;
388	    if (strncmp(p, "ws://", 5) != 0) {
389	        web_set_err(err, err_len, "unsupported websocket URL: %s", ws_url);
390	        return -1;
391	    }
392	    p += 5;
393	    const char *slash = strchr(p, '/');
394	    if (!slash) {
395	        web_set_err(err, err_len, "malformed websocket URL");
396	        return -1;
397	    }
398	    char hostport[256];
399	    size_t hp_len = (size_t)(slash - p);
400	    if (hp_len >= sizeof(hostport)) hp_len = sizeof(hostport) - 1;
401	    memcpy(hostport, p, hp_len);
402	    hostport[hp_len] = '\0';
403	    char *colon = strrchr(hostport, ':');
404	    int port = 80;
405	    if (colon) {
406	        *colon = '\0';
407	        port = atoi(colon + 1);
408	    }
409	    const char *host = hostport;
410	    int fd = web_tcp_connect(host, port, DS4_WEB_CONNECT_TIMEOUT_MS, err, err_len);
411	    if (fd < 0) return -1;
412	
413	    unsigned char rnd[16];
414	    web_random_bytes(rnd, sizeof(rnd));
415	    char *key = web_base64(rnd, sizeof(rnd));
416	    web_buf req = {0};
417	    char line[512];
418	    snprintf(line, sizeof(line),
419	             "GET %s HTTP/1.1\r\n"
420	             "Host: %s:%d\r\n"
421	             "Upgrade: websocket\r\n"
422	             "Connection: Upgrade\r\n"
423	             "Sec-WebSocket-Key: %s\r\n"
424	             "Sec-WebSocket-Version: 13\r\n\r\n",
425	             slash, host, port, key);
426	    web_buf_puts(&req, line);
427	    free(key);
428	    if (web_write_all(fd, req.ptr, req.len) != 0) {
429	        web_set_err(err, err_len, "websocket handshake write failed");
430	        close(fd);
431	        free(req.ptr);
432	        return -1;
433	    }
434	    free(req.ptr);
435	
436	    web_buf resp = {0};
437	    char tmp[1024];
438	    double deadline = web_now_sec() + (double)DS4_WEB_CONNECT_TIMEOUT_MS / 1000.0;
439	    while (!strstr(resp.ptr ? resp.ptr : "", "\r\n\r\n")) {
440	        if (web_set_cancel_err(ws ? ws->web : NULL, err, err_len)) {
441	            close(fd);
442	            free(resp.ptr);
443	            return -1;
444	        }
445	        double now = web_now_sec();
446	        if (now >= deadline) {
447	            web_set_err(err, err_len, "websocket handshake read failed");
448	            close(fd);
449	            free(resp.ptr);
450	            return -1;
451	        }
452	        int slice = 100;
453	        int remaining = (int)((deadline - now) * 1000.0);
454	        if (remaining < slice) slice = remaining > 0 ? remaining : 1;
455	        ssize_t n = web_read_some(fd, tmp, sizeof(tmp), slice);
456	        if (n < 0) {
457	            web_set_err(err, err_len, "websocket handshake read failed");
458	            close(fd);
459	            free(resp.ptr);
460	            return -1;
461	        }
462	        if (n == 0) continue;
463	        web_buf_append(&resp, tmp, (size_t)n);
464	        if (resp.len > 8192) break;
465	    }
466	    bool ok = resp.ptr && strstr(resp.ptr, " 101 ") != NULL;
467	    free(resp.ptr);
468	    if (!ok) {
469	        web_set_err(err, err_len, "websocket handshake rejected");
470	        close(fd);
471	        return -1;
472	    }
473	    ws->fd = fd;
474	    ws->next_id = 1;
475	    return 0;
476	}
477	
478	static void web_ws_close(cdp_ws *ws) {
479	    if (ws && ws->fd >= 0) {
480	        close(ws->fd);
481	        ws->fd = -1;
482	    }
483	}
484	
485	static int web_read_exact(cdp_ws *ws, unsigned char *buf, size_t len,
486	                          int timeout_ms, char *err, size_t err_len) {
487	    size_t off = 0;
488	    double deadline = web_now_sec() + (double)timeout_ms / 1000.0;
489	    while (off < len) {
490	        if (web_set_cancel_err(ws ? ws->web : NULL, err, err_len)) return -1;
491	        double now = web_now_sec();
492	        if (now >= deadline) {
493	            web_set_err(err, err_len, "websocket read timeout");
494	            return -1;
495	        }
496	        int slice = 100;
497	        int remaining = (int)((deadline - now) * 1000.0);
498	        if (remaining < slice) slice = remaining > 0 ? remaining : 1;
499	        ssize_t n = web_read_some(ws->fd, (char *)buf + off, len - off, slice);
500	        if (n < 0) {
501	            web_set_err(err, err_len, "websocket frame read failed");
502	            return -1;
503	        }
504	        if (n == 0) continue;
505	        off += (size_t)n;
506	    }
507	    return 0;
508	}
509	
510	static int web_ws_send_text(cdp_ws *ws, const char *text,
511	                            char *err, size_t err_len) {
512	    size_t len = strlen(text);
513	    web_buf frame = {0};
514	    unsigned char hdr[14];
515	    size_t h = 0;
516	    hdr[h++] = 0x81;
517	    if (len < 126) {
518	        hdr[h++] = 0x80 | (unsigned char)len;
519	    } else if (len <= 0xffff) {
520	        hdr[h++] = 0x80 | 126;
521	        hdr[h++] = (unsigned char)(len >> 8);
522	        hdr[h++] = (unsigned char)len;
523	    } else {
524	        hdr[h++] = 0x80 | 127;
525	        for (int i = 7; i >= 0; i--) hdr[h++] = (unsigned char)((uint64_t)len >> (i * 8));
526	    }
527	    unsigned char mask[4];
528	    web_random_bytes(mask, sizeof(mask));
529	    for (int i = 0; i < 4; i++) hdr[h++] = mask[i];
530	    web_buf_append(&frame, (const char *)hdr, h);
531	    for (size_t i = 0; i < len; i++) {
532	        char c = text[i] ^ mask[i & 3];
533	        web_buf_append(&frame, &c, 1);
534	    }
535	    int rc = web_write_all(ws->fd, frame.ptr, frame.len);
536	    free(frame.ptr);
537	    if (rc != 0) {
538	        web_set_err(err, err_len, "websocket write failed: %s", strerror(errno));
539	        return -1;
540	    }
541	    return 0;
542	}
