544	static int web_ws_send_pong(cdp_ws *ws, const unsigned char *payload, size_t len) {
545	    if (len > 125) len = 125;
546	    unsigned char hdr[2 + 4 + 125];
547	    hdr[0] = 0x8a;
548	    hdr[1] = 0x80 | (unsigned char)len;
549	    unsigned char mask[4];
550	    web_random_bytes(mask, sizeof(mask));
551	    memcpy(hdr + 2, mask, 4);
552	    for (size_t i = 0; i < len; i++) hdr[6 + i] = payload[i] ^ mask[i & 3];
553	    return web_write_all(ws->fd, hdr, 6 + len);
554	}
