556	static char *web_ws_read_message(cdp_ws *ws, char *err, size_t err_len) {
557	    web_buf msg = {0};
558	    for (;;) {
559	        unsigned char h[2];
560	        if (web_read_exact(ws, h, 2, DS4_WEB_CDP_TIMEOUT_MS, err, err_len) != 0) {
561	            free(msg.ptr);
562	            return NULL;
563	        }
564	        bool fin = (h[0] & 0x80) != 0;
565	        int opcode = h[0] & 0x0f;
566	        bool masked = (h[1] & 0x80) != 0;
567	        uint64_t len = h[1] & 0x7f;
568	        if (len == 126) {
569	            unsigned char x[2];
570	            if (web_read_exact(ws, x, 2, DS4_WEB_CDP_TIMEOUT_MS, err, err_len) != 0) goto fail;
571	            len = ((uint64_t)x[0] << 8) | x[1];
572	        } else if (len == 127) {
573	            unsigned char x[8];
574	            if (web_read_exact(ws, x, 8, DS4_WEB_CDP_TIMEOUT_MS, err, err_len) != 0) goto fail;
575	            len = 0;
576	            for (int i = 0; i < 8; i++) len = (len << 8) | x[i];
577	        }
578	        unsigned char mask[4] = {0};
579	        if (masked && web_read_exact(ws, mask, 4, DS4_WEB_CDP_TIMEOUT_MS, err, err_len) != 0)
580	            goto fail;
581	        if (len > DS4_WEB_MAX_RESULT_BYTES * 4ULL) {
582	            web_set_err(err, err_len, "websocket message too large");
583	            free(msg.ptr);
584	            return NULL;
585	        }
586	        unsigned char *payload = web_xmalloc((size_t)len + 1);
587	        if (len && web_read_exact(ws, payload, (size_t)len,
588	                                  DS4_WEB_CDP_TIMEOUT_MS, err, err_len) != 0) {
589	            free(payload);
590	            goto fail;
591	        }
592	        for (uint64_t i = 0; masked && i < len; i++) payload[i] ^= mask[i & 3];
593	        payload[len] = '\0';
594	        if (opcode == 0x8) {
595	            free(payload);
596	            web_set_err(err, err_len, "websocket closed");
597	            free(msg.ptr);
598	            return NULL;
599	        } else if (opcode == 0x9) {
600	            web_ws_send_pong(ws, payload, (size_t)len);
601	            free(payload);
602	            continue;
603	        } else if (opcode == 0x1 || opcode == 0x0) {
604	            web_buf_append(&msg, (const char *)payload, (size_t)len);
605	            free(payload);
606	            if (fin) return web_buf_take(&msg);
607	        } else {
608	            free(payload);
609	        }
610	    }
611	fail:
612	    if (err && err_len && !err[0]) web_set_err(err, err_len, "websocket frame read failed");
613	    free(msg.ptr);
614	    return NULL;
615	}
