664	static int web_hex4(const char *p) {
665	    int v = 0;
666	    for (int i = 0; i < 4; i++) {
667	        char c = p[i];
668	        int x;
669	        if (c >= '0' && c <= '9') x = c - '0';
670	        else if (c >= 'a' && c <= 'f') x = c - 'a' + 10;
671	        else if (c >= 'A' && c <= 'F') x = c - 'A' + 10;
672	        else return -1;
673	        v = (v << 4) | x;
674	    }
675	    return v;
676	}
