847	static bool web_wait_navigated_ready(cdp_ws *ws, const char *url,
848	                                     char *err, size_t err_len) {
849	    (void)url;
850	    long last_len = -1;
851	    int stable = 0;
852	    bool saw_real_url = false;
853	
854	    for (int i = 0; i < 100; i++) {
855	        if (web_set_cancel_err(ws ? ws->web : NULL, err, err_len)) return false;
856	        char *href = NULL;
857	        char *ready = NULL;
858	        long text_len = 0;
859	        bool ok = web_page_probe(ws, &href, &ready, &text_len, err, err_len);
860	        if (!ok) {
861	            free(href);
862	            free(ready);
863	            if (!web_sleep_ms(ws ? ws->web : NULL, 250)) {
864	                web_set_err(err, err_len, "interrupted");
865	                return false;
866	            }
867	            continue;
868	        }
869	
870	        bool real_url = href && href[0] &&
871	                        strcmp(href, "about:blank") &&
872	                        strncmp(href, "chrome://", 9);
873	        bool ready_state = ready &&
874	            (!strcmp(ready, "complete") || !strcmp(ready, "interactive"));
875	        if (real_url) saw_real_url = true;
876	        if (text_len > 0 && text_len == last_len) stable++;
877	        else stable = 0;
878	        last_len = text_len;
879	
880	        free(href);
881	        free(ready);
882	
883	        if (saw_real_url && ready_state && text_len > 0 && stable >= 2) {
884	            if (web_sleep_ms(ws ? ws->web : NULL, 500)) return true;
885	            web_set_err(err, err_len, "interrupted");
886	            return false;
887	        }
888	        if (saw_real_url && ready_state && i >= 24) return true;
889	        if (!web_sleep_ms(ws ? ws->web : NULL, 250)) {
890	            web_set_err(err, err_len, "interrupted");
891	            return false;
892	        }
893	    }
894	    return true;
895	}
