911	static bool web_scroll_dynamic_page(cdp_ws *ws, char *err, size_t err_len) {
912	    const char *expr =
913	        "(() => new Promise(resolve => {"
914	        "const root=()=>document.scrollingElement||document.documentElement||document.body;"
915	        "const blockSel='h1,h2,h3,h4,h5,h6,p,li,pre,blockquote,td,th,[id=\"content-text\"],[class*=\"comment-body\"],[class*=\"comment-content\"],[data-testid*=\"comment-text\"]';"
916	        "const lazySel='[onscroll],[loading=\"lazy\"],[data-src],[data-lazy],[class*=\"lazy\"],[class*=\"infinite\"],[class*=\"virtual\"],[role=\"feed\"],[id*=\"comment\"],[class*=\"comment\"],[data-testid*=\"comment\"]';"
917	        "const hookCount=()=>{let n=0;try{if(window.onscroll)n++;if(document.onscroll)n++;if(document.body&&document.body.onscroll)n++;}catch(e){}"
918	        "try{if(typeof getEventListeners==='function'){for(const o of [window,document,document.body]){if(!o)continue;const ev=getEventListeners(o);if(ev&&ev.scroll)n+=ev.scroll.length;}}}catch(e){}"
919	        "try{n+=document.querySelectorAll(lazySel).length;}catch(e){}return n;};"
920	        "const metrics=()=>{const r=root();return {"
921	        "height:r?r.scrollHeight:0,"
922	        "view:innerHeight||900,"
923	        "y:scrollY||(r&&r.scrollTop)||0,"
924	        "text:((document.body&&document.body.innerText)||'').length,"
925	        "links:document.links?document.links.length:0,"
926	        "blocks:document.body?document.body.querySelectorAll(blockSel).length:0,"
927	        "hooks:hookCount()};};"
928	        "const sig=m=>[m.height,m.text,m.links,m.blocks].join('|');"
929	        "const grew=(a,b)=>b.height>a.height+20||b.text>a.text+200||b.links>a.links+2||b.blocks>a.blocks+2;"
930	        "const scrollOnce=()=>{const r=root();if(!r)return;"
931	        "const h=Math.max(700,Math.floor((innerHeight||900)*0.85));"
932	        "window.scrollTo(0,Math.min(r.scrollHeight,(scrollY||r.scrollTop||0)+h));};"
933	        "let last=metrics(),lastSig=sig(last),same=0,steps=0;"
934	        "const scrollable=last.height>last.view*1.35;"
935	        "if(!scrollable||last.hooks===0){resolve('scroll skipped hooks='+last.hooks+' text='+last.text);return;}"
936	        "const tick=()=>{"
937	        "if(steps>=28){resolve('scrolled '+steps+' text='+last.text);return;}"
938	        "const before=last;"
939	        "scrollOnce();steps++;"
940	        "setTimeout(()=>{const now=metrics(),nowSig=sig(now);"
941	        "if(nowSig===lastSig)same++;else same=0;"
942	        "const loaded=grew(before,now);"
943	        "last=now;lastSig=nowSig;"
944	        "if(steps===1&&!loaded){resolve('scroll probe unchanged text='+now.text);return;}"
945	        "const atBottom=now.y+now.view+20>=now.height;"
946	        "if(same>=4||(atBottom&&same>=1)){resolve('scrolled '+steps+' text='+now.text);return;}"
947	        "tick();},900);"
948	        "};tick();"
949	        "}))()";
950	    if (web_set_cancel_err(ws ? ws->web : NULL, err, err_len)) return false;
951	
952	    char local_err[160] = {0};
953	    char *res = web_cdp_eval_string(ws, expr, local_err, sizeof(local_err));
954	    if (!res && web_err_is_interrupted(local_err)) {
955	        web_set_err(err, err_len, "interrupted");
956	        return false;
957	    }
958	    free(res);
959	    if (web_set_cancel_err(ws ? ws->web : NULL, err, err_len)) return false;
960	    return true;
961	}
