1023	static bool web_spawn_chrome(ds4_web *web, char *err, size_t err_len) {
1024	    if (!web_mkdir_p(web->profile_dir)) {
1025	        web_set_err(err, err_len, "failed to create Chrome profile dir %s: %s",
1026	                    web->profile_dir, strerror(errno));
1027	        return false;
1028	    }
1029	    char *exe = web_chrome_executable();
1030	#ifdef __APPLE__
1031	    const char *mac_app_name = web_macos_chrome_app_name();
1032	    bool launched_via_open = mac_app_name != NULL && access("/usr/bin/open", X_OK) == 0;
1033	#else
1034	    bool launched_via_open = false;
1035	#endif
1036	    char port_arg[64], profile_arg[PATH_MAX + 64];
1037	    snprintf(port_arg, sizeof(port_arg), "--remote-debugging-port=%d", web->port);
1038	    snprintf(profile_arg, sizeof(profile_arg), "--user-data-dir=%s", web->profile_dir);
1039	    pid_t pid = fork();
1040	    if (pid < 0) {
1041	        web_set_err(err, err_len, "failed to fork Chrome: %s", strerror(errno));
1042	        free(exe);
1043	        return false;
1044	    }
1045	    if (pid == 0) {
1046	        int nullfd = open("/dev/null", O_RDWR);
1047	        if (nullfd >= 0) {
1048	            dup2(nullfd, STDOUT_FILENO);
1049	            dup2(nullfd, STDERR_FILENO);
1050	            if (nullfd > 2) close(nullfd);
1051	        }
1052	#ifdef __APPLE__
1053	        if (launched_via_open) {
1054	            execlp("/usr/bin/open", "open", "-g", "-na", mac_app_name,
1055	                   "--args", port_arg, "--remote-allow-origins=*",
1056	                   profile_arg, "--no-first-run", "--no-default-browser-check",
1057	                   "--disable-sync", "--use-mock-keychain", "--password-store=basic",
1058	                   "--mute-audio", "about:blank", (char *)NULL);
1059	        } else {
1060	            execlp(exe, exe, port_arg, "--remote-allow-origins=*",
1061	                   profile_arg, "--no-first-run", "--no-default-browser-check",
1062	                   "--disable-sync", "--use-mock-keychain", "--password-store=basic",
1063	                   "--mute-audio", "about:blank", (char *)NULL);
1064	        }
1065	#else
1066	        if (geteuid() == 0) {
1067	            execlp(exe, exe, port_arg, "--remote-allow-origins=*",
1068	                   profile_arg, "--no-first-run", "--no-default-browser-check",
1069	                   "--disable-sync", "--password-store=basic", "--no-sandbox",
1070	                   "--mute-audio", "about:blank", (char *)NULL);
1071	        } else {
1072	            execlp(exe, exe, port_arg, "--remote-allow-origins=*",
1073	                   profile_arg, "--no-first-run", "--no-default-browser-check",
1074	                   "--disable-sync", "--password-store=basic",
1075	                   "--mute-audio", "about:blank", (char *)NULL);
1076	        }
1077	#endif
1078	        _exit(127);
1079	    }
1080	    free(exe);
1081	    web->chrome_pid = pid;
1082	    for (int i = 0; i < 80; i++) {
1083	        if (web_set_cancel_err(web, err, err_len)) return false;
1084	        if (web_cdp_alive(web)) {
1085	            web_log(web, "Chrome browser session is ready");
1086	            return true;
1087	        }
1088	        int status = 0;
1089	        pid_t rc = waitpid(pid, &status, WNOHANG);
1090	        if (rc == pid) {
1091	            web->chrome_pid = 0;
1092	            if (launched_via_open) continue;
1093	            web_set_err(err, err_len, "Chrome exited before CDP became ready");
1094	            return false;
1095	        }
1096	        if (!web_sleep_ms(web, 250)) {
1097	            web_set_err(err, err_len, "interrupted");
1098	            return false;
1099	        }
1100	    }
1101	    web_set_err(err, err_len, "Chrome did not expose CDP on port %d", web->port);
1102	    return false;
1103	}
