1105	static bool web_ensure_browser(ds4_web *web, char *err, size_t err_len) {
1106	    if (web_cdp_alive(web)) return true;
1107	    if (web->chrome_pid > 0) {
1108	        int status = 0;
1109	        waitpid(web->chrome_pid, &status, WNOHANG);
1110	        web->chrome_pid = 0;
1111	    }
1112	    if (!web->browser_allowed) {
1113	        if (!web->confirm) {
1114	            web_set_err(err, err_len,
1115	                        "starting a visible Chrome browser requires interactive approval");
1116	            return false;
1117	        }
1118	        if (!web->confirm(web->confirm_privdata,
1119	                          "The web tool wants to start a visible Chrome browser. Allow? (y/n) ",
1120	                          err, err_len))
1121	        {
1122	            if (err && !err[0]) web_set_err(err, err_len, "user denied Chrome browser start");
1123	            return false;
1124	        }
1125	        web->browser_allowed = true;
1126	    }
1127	    return web_spawn_chrome(web, err, err_len);
1128	}
