1207	static const char *web_click_google_consent_js =
1208	"(() => {"
1209	"const clean=s=>(s||'').replace(/\\s+/g,' ').trim();"
1210	"const pats=[/accept all/i,/i agree/i,/agree/i,/accetta tutto/i,/tout accepter/i,/aceptar todo/i,/alle akzeptieren/i];"
1211	"const els=[...document.querySelectorAll('button,[role=button],input[type=submit],a')];"
1212	"for (const el of els){const t=clean(el.innerText||el.value||el.textContent);"
1213	"if(!t)continue; if(pats.some(p=>p.test(t))){el.click(); return 'clicked '+t;}}"
1214	"return '';"
1215	"})()";
