1217	static const char *web_extract_search_js =
1218	"(() => {"
1219	"const clean=s=>(s||'').replace(/\\s+/g,' ').trim();"
1220	"const esc=s=>clean(s).replace(/\\\\/g,'\\\\\\\\').replace(/\\[/g,'\\\\[').replace(/\\]/g,'\\\\]').replace(/\\n/g,' ');"
1221	"const visible=el=>{const r=el.getBoundingClientRect();const st=getComputedStyle(el);return r.width>0&&r.height>0&&st.display!=='none'&&st.visibility!=='hidden'&&st.opacity!=='0';};"
1222	"const bad=h=>(/(^|\\.)google\\./.test(h)||/(^|\\.)gstatic\\./.test(h)||/(^|\\.)googleusercontent\\./.test(h));"
1223	"const lines=['# Google search results','',`URL: ${location.href}`,'','## Visible links'];"
1224	"const seen=new Set();"
1225	"for(const a of document.querySelectorAll('a[href]')){if(!visible(a))continue;let href=a.href||'';"
1226	"try{const u=new URL(href);if(u.pathname==='/url'&&u.searchParams.get('q'))href=u.searchParams.get('q');}catch{}"
1227	"let u;try{u=new URL(href);}catch{continue;}if(!/^https?:$/.test(u.protocol))continue;if(bad(u.hostname))continue;"
1228	"const text=esc(a.innerText||a.textContent);if(text.length<3)continue;if(seen.has(u.href))continue;seen.add(u.href);"
1229	"lines.push(`- [${text.slice(0,180)}](${u.href})`);if(seen.size>=20)break;}"
1230	"lines.push('','## Text snapshot',clean(document.body.innerText).slice(0,1200));"
1231	"return lines.join('\\n');"
1232	"})()";
1233	
1234	static const char *web_extract_page_js =
1235	"(() => {"
1236	"const clean=s=>(s||'').replace(/\\s+/g,' ').trim();"
1237	"const esc=s=>clean(s).replace(/\\\\/g,'\\\\\\\\').replace(/\\[/g,'\\\\[').replace(/\\]/g,'\\\\]').replace(/\\n/g,' ');"
1238	"const visible=el=>{const r=el.getBoundingClientRect();const st=getComputedStyle(el);return r.width>0&&r.height>0&&st.display!=='none'&&st.visibility!=='hidden'&&st.opacity!=='0';};"
1239	"const inline=n=>{if(!n)return'';if(n.nodeType===3)return n.nodeValue;if(n.nodeType!==1)return'';const el=n;"
1240	"if(el.tagName==='SCRIPT'||el.tagName==='STYLE'||el.tagName==='NOSCRIPT')return'';"
1241	"if(el.tagName==='A'){const t=esc(el.innerText||el.textContent);const h=el.href||'';return t&&h?`[${t}](${h})`:t;}"
1242	"if(el.tagName==='CODE')return '`'+clean(el.innerText||el.textContent).replace(/`/g,'\\\\`')+'`';"
1243	"return [...el.childNodes].map(inline).join('');};"
1244	"const lines=[`# ${clean(document.title)||location.href}`,'',`URL: ${location.href}`,'','## Content'];"
1245	"const blocks=[...document.body.querySelectorAll('h1,h2,h3,h4,h5,h6,p,li,pre,blockquote,td,th,[id=\"content-text\"],[class*=\"comment-body\"],[class*=\"comment-content\"],[data-testid*=\"comment-text\"]')];"
1246	"const seen=new Set();"
1247	"for(const el of blocks){if(!visible(el))continue;let s='';const tag=el.tagName;"
1248	"if(/^H[1-6]$/.test(tag)){s='#'.repeat(Number(tag[1]))+' '+inline(el);}"
1249	"else if(tag==='LI'){s='- '+inline(el);}"
1250	"else if(tag==='PRE'){s='```\\n'+(el.innerText||el.textContent||'').trimEnd()+'\\n```';}"
1251	"else if(tag==='BLOCKQUOTE'){s='> '+clean(el.innerText||el.textContent);}"
1252	"else{s=inline(el);}s=s.trim();if(!s||seen.has(s))continue;seen.add(s);lines.push('',s);"
1253	"if(lines.join('\\n').length>900000){lines.push('','[Content truncated by browser extractor.]');break;}}"
1254	"lines.push('','## Visible links');let n=0;const linkSeen=new Set();"
1255	"for(const a of document.querySelectorAll('a[href]')){if(!visible(a))continue;const t=esc(a.innerText||a.textContent);if(t.length<3)continue;"
1256	"let u;try{u=new URL(a.href);}catch{continue;}if(!/^https?:$/.test(u.protocol)||linkSeen.has(u.href))continue;linkSeen.add(u.href);"
1257	"lines.push(`- [${t.slice(0,160)}](${u.href})`);if(++n>=80)break;}"
1258	"return lines.join('\\n');"
1259	"})()";
