1261	static char *web_run_page_js(ds4_web *web, const char *url, const char *js,
1262	                             bool dynamic_scroll,
1263	                             char *err, size_t err_len) {
1264	    if (!web_ensure_browser(web, err, err_len)) return NULL;
1265	    web_tab tab = {0};
1266	    if (!web_open_tab(web, "about:blank", &tab, err, err_len)) return NULL;
1267	    cdp_ws ws = {.fd = -1, .web = web};
1268	    if (web_ws_connect(tab.ws_url, &ws, err, err_len) != 0) {
1269	        web_close_tab(web, &tab);
1270	        web_tab_free(&tab);
1271	        return NULL;
1272	    }
1273	    if (!web_cdp_prepare_page(&ws, err, err_len)) {
1274	        web_ws_close(&ws);
1275	        web_close_tab(web, &tab);
1276	        web_tab_free(&tab);
1277	        return NULL;
1278	    }
1279	    if (!web_cdp_navigate(&ws, url, err, err_len) ||
1280	        !web_wait_navigated_ready(&ws, url, err, err_len))
1281	    {
1282	        web_ws_close(&ws);
1283	        web_close_tab(web, &tab);
1284	        web_tab_free(&tab);
1285	        return NULL;
1286	    }
1287	    char *clicked = web_cdp_eval_string(&ws, web_click_google_consent_js, err, err_len);
1288	    if (clicked && clicked[0]) {
1289	        web_log(web, clicked);
1290	        if (!web_sleep_ms(web, 1500)) {
1291	            free(clicked);
1292	            web_set_err(err, err_len, "interrupted");
1293	            web_ws_close(&ws);
1294	            web_close_tab(web, &tab);
1295	            web_tab_free(&tab);
1296	            return NULL;
1297	        }
1298	        char wait_err[160] = {0};
1299	        if (!web_wait_navigated_ready(&ws, url, wait_err, sizeof(wait_err)) &&
1300	            web_err_is_interrupted(wait_err))
1301	        {
1302	            free(clicked);
1303	            web_set_err(err, err_len, "interrupted");
1304	            web_ws_close(&ws);
1305	            web_close_tab(web, &tab);
1306	            web_tab_free(&tab);
1307	            return NULL;
1308	        }
1309	    }
1310	    free(clicked);
1311	    if (dynamic_scroll && !web_scroll_dynamic_page(&ws, err, err_len)) {
1312	        web_ws_close(&ws);
1313	        web_close_tab(web, &tab);
1314	        web_tab_free(&tab);
1315	        return NULL;
1316	    }
1317	    char *out = web_cdp_eval_string(&ws, js, err, err_len);
1318	    web_ws_close(&ws);
1319	    web_close_tab(web, &tab);
1320	    web_tab_free(&tab);
1321	    return out;
1322	}
